import { read, utils } from 'https://cdn.jsdelivr.net/npm/xlsx@0.18.5/+esm';
const wb = read(data.data, { type: 'array', ...(data.opts ?? {}) });
const ws = wb.Sheets[wb.SheetNames[0]];
const html = utils.sheet_to_html(ws);              // 预览:artifact/codex → getElementById('xlsx').innerHTML=html;widget → shadow 内容器.innerHTML=html
const rows = utils.sheet_to_json(ws, { header: 1 }); // 或取二维行数组喂给 grid;多 sheet 遍历 wb.SheetNames
